import { Layer } from '@vis.gl/react-maplibre';

import { calculateCircleTranslate } from './utils/calculate-circle-translate.js';
import {
  BUBBLE_OUTLINE_STROKE,
  ICON_BACKGROUND_OPACITY,
} from '../../constants.js';

interface BackgroundLayerProps {
  background: boolean;
  beforeId: string;
  source: string;
  radius: number;
  iconAnchor: 'bottom' | 'center';
}

export const BackgroundLayer = (props: BackgroundLayerProps) => {
  const { background, beforeId, source, radius, iconAnchor } = props;
  const circleTranslate = calculateCircleTranslate(iconAnchor, radius);

  return (
    <Layer
      type="circle"
      beforeId={beforeId}
      source={source}
      paint={{
        'circle-color': [
          'case',
          ['boolean', ['feature-state', 'hover'], false],
          ['get', '__hoveredBackgroundColor'],
          ['get', '__backgroundColor'],
        ],
        'circle-radius': radius,
        'circle-opacity': [
          'case',
          ['boolean', background, false],
          ICON_BACKGROUND_OPACITY,
          ['boolean', ['feature-state', 'hover'], false],
          ICON_BACKGROUND_OPACITY,
          0,
        ],
        'circle-stroke-width': [
          'case',
          ['boolean', ['feature-state', 'active'], false],
          BUBBLE_OUTLINE_STROKE,
          0,
        ],
        'circle-translate': circleTranslate,
      }}
    />
  );
};
